use std::{net::SocketAddr, sync::Arc};

use anyhow::Result;
use tokio::{net::UdpSocket, sync::mpsc};

#[derive(Debug)]
struct Header {
    id: u16,
    /// Query(true) or Response(false)
    qr: bool,
    opcode: u8, // 4 bits
    aa: bool,
    tc: bool,
    rd: bool,
    ra: bool,
    z: u8, // 3 bits, reserved for future use
    rcode: u8,
    qdcount: u16,
    ancount: u16,
    nscount: u16,
    arcount: u16,
}

#[derive(Debug)]
struct Question {
    qname: String, // Each label has a u8 for length of label. 0x003 0x777777 = www
    qtype: u16,
    qclass: u16,
}

#[derive(Debug)]
struct Answer {
    name: String, // Each label has a u8 for length of label. 0x003 0x777777 = www
    r#type: u16,
    class: u16,
    ttl: u32,
    rdlength: u16,
    rdata: Vec<u8>, // depends on type field
}

#[derive(Debug)]
struct Request {
    header: Header,
    question: Question,
}

fn parse_dns_request(bytes: &[u8]) -> Result<Request> {
    let id = u16::from_be_bytes(bytes[0..2].try_into()?);

    let flags = bytes[2];
    let qr = flags & 1 != 0;
    let opcode = (flags >> 1) & 0x0F;
    let aa = (flags >> 4) & 1 != 0;
    let tc = (flags >> 5) & 1 != 0;
    let rd = (flags >> 6) & 1 != 0;
    let ra = (flags >> 7) & 1 != 0;

    let z = bytes[3] & 0x0F;
    let rcode = (bytes[3] >> 4) & 0x0F;

    let header = Header {
        id,
        qr,
        opcode,
        aa,
        tc,
        rd,
        ra,
        z,
        rcode,
        qdcount: u16::from_le_bytes(bytes[4..=5].try_into()?),
        ancount: u16::from_le_bytes(bytes[6..=7].try_into()?),
        nscount: u16::from_le_bytes(bytes[8..=9].try_into()?),
        arcount: u16::from_le_bytes(bytes[10..=11].try_into()?),
    };

    let mut qname = String::new();
    let mut pos = 12;
    let mut next_chunk: usize = bytes[pos] as usize;

    while next_chunk != 0 {
        qname.push_str(String::from_utf8(bytes[pos..=pos+next_chunk].try_into()?)?.as_str());
        pos += next_chunk;
        next_chunk = bytes[pos] as usize;
    }

    pos += 1;

    let question = Question {
        qname,
        qtype: u16::from_be_bytes(bytes[pos..=pos+1].try_into()?),
        qclass: u16::from_be_bytes(bytes[pos+2..=pos+3].try_into()?),
    };

    Ok(Request { header, question })
}

#[tokio::main]
async fn main() -> anyhow::Result<()> {
    let socket = UdpSocket::bind("0.0.0.0:53".parse::<SocketAddr>()?).await?;
    let r = Arc::new(socket);
    let s = r.clone();

    let (tx, mut rx) = mpsc::channel::<(Vec<u8>, SocketAddr)>(1_000);

    tokio::spawn(async move {
        while let Some((bytes, addr)) = rx.recv().await {
            let len = s.send_to(&bytes, &addr).await.unwrap();
            println!("{:?} bytes sent", len);
        }
    });

    let mut buf = [0; 1024];
    loop {
        let (len, addr) = r.recv_from(&mut buf).await?;

        println!("{:?} bytes received from {:?}", len, addr);
        println!("raw: {:?}", buf);
        println!("utf8 lossy: {}", String::from_utf8_lossy(&buf));

        tx.send((buf[..len].to_vec(), addr)).await.unwrap();
    }

    Ok(())
}


